import{_ as t,o as d,c as r,a2 as o}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"Orrery — Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),a={name:"index.md"};function n(i,e,s,c,h,l){return d(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="orrery-—-documentation" tabindex="-1">Orrery — Documentation <a class="header-anchor" href="#orrery-—-documentation" aria-label="Permalink to &quot;Orrery — Documentation&quot;">​</a></h1><p>This directory contains the full documentation for Orrery, organised into five sections plus a user guide and translator guide.</p><h2 id="read-first" tabindex="-1">Read first <a class="header-anchor" href="#read-first" aria-label="Permalink to &quot;Read first&quot;">​</a></h2><ul><li><strong><a href="./user-guide"><code>user-guide.md</code></a></strong> — read-this-first walk-through of the live app, screen by screen, with screenshots. Start here if you want to use Orrery.</li><li><strong><a href="./i18n-style-guide"><code>i18n-style-guide.md</code></a></strong> — binding glossary for translators (per ADR-033).</li></ul><h2 id="concept-package" tabindex="-1">Concept package <a class="header-anchor" href="#concept-package" aria-label="Permalink to &quot;Concept package&quot;">​</a></h2><p><code>concept/</code> — the founding narrative documents (00–05). Read these to understand what Orrery is, why it was built, and what design and physics decisions were made during prototyping. Start with <code>02_Project_Concept.md</code>.</p><p><code>prototypes/</code> — six working HTML prototype files (P01–P06). These are the ground truth for all design and physics decisions. Open them directly in a browser.</p><h2 id="phase-2-—-definition-documents" tabindex="-1">Phase 2 — Definition documents <a class="header-anchor" href="#phase-2-—-definition-documents" aria-label="Permalink to &quot;Phase 2 — Definition documents&quot;">​</a></h2><p>Four folders, three planes:</p><p><strong>Product plane</strong> (<code>prd/</code>) — what changes for the user. Start with <code>PA.md</code> (audiences, promises, principles). Each PRD-NNN describes one screen.</p><p><strong>UX plane</strong> (<code>uxs/</code>) — what does it look like. Start with <code>IA.md</code> (surfaces, navigation, shared tokens). Each UXS-NNN is the static visual contract for one screen, verified against the prototype.</p><p><strong>Tech plane — open questions</strong> (<code>rfc/</code>) — technical questions with alternatives. RFCs close into ADRs when implementation evidence arrives at each slice gate. See IMPLEMENTATION.md for slice definitions.</p><p><strong>Tech plane — locked decisions</strong> (<code>adr/</code>) — committed decisions, append-only. Start with <code>TA.md</code> (components, contracts, constraints, stack, §map). Each ADR-NNN is a single locked decision.</p><h2 id="quick-reference" tabindex="-1">Quick reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>I want to...</th><th>Read...</th></tr></thead><tbody><tr><td>Use Orrery</td><td><code>user-guide.md</code></td></tr><tr><td>Understand what Orrery is</td><td><code>concept/02_Project_Concept.md</code></td></tr><tr><td>See the original concept</td><td><code>prototypes/P01_solar-system-explorer.html</code></td></tr><tr><td>Understand the audiences and promises</td><td><code>prd/PA.md</code></td></tr><tr><td>See the design system</td><td><code>uxs/IA.md</code> + any <code>UXS-NNN.md</code></td></tr><tr><td>Understand the tech stack</td><td><code>adr/TA.md</code></td></tr><tr><td>Find open technical questions</td><td><code>rfc/index.md</code></td></tr><tr><td>Find locked decisions</td><td><code>adr/index.md</code></td></tr><tr><td>Translate Orrery into a new language</td><td><code>i18n-style-guide.md</code></td></tr><tr><td>Understand what to build next</td><td><code>../IMPLEMENTATION.md</code></td></tr></tbody></table>',15)])])}const m=t(a,[["render",n]]);export{u as __pageData,m as default};
